package io.spdigital.skalbox.ubm.controller;

import io.spdigital.skalbox.accounts.service.AccountService;
import io.spdigital.skalbox.chart.model.dto.BDLChart;
import io.spdigital.skalbox.chart.model.dto.MDHChart;
import io.spdigital.skalbox.chart.service.ChartService;
import io.spdigital.skalbox.logging.Loggable;
import io.spdigital.skalbox.smrd.dto.MeterReadingSubmission;
import io.spdigital.skalbox.smrd.dto.RetrieveScalarMeterInfo;
import io.spdigital.skalbox.smrd.service.SMRDService;
import io.spdigital.skalbox.ubm.dto.MeterReading;
import io.spdigital.skalbox.ubm.dto.PubConcession;
import io.spdigital.skalbox.ubm.dto.PubConcession.ResponseCsv;
import io.spdigital.skalbox.ubm.dto.StatisticRpBillPrefRes;
import io.spdigital.skalbox.ubm.dto.SubscriptionTrail;
import io.spdigital.skalbox.ubm.service.TrailService;
import io.spdigital.skalbox.web.common.security.SkalboxM2MSecured;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.List;

import static io.spdigital.skalbox.chart.model.dto.ChartConstants.CSV_MONTHLY;

@Slf4j
@RestController
@RequestMapping("/ubm/trail")
@RequiredArgsConstructor
public class TrailController {

	private final TrailService trailService;

	private final SMRDService smrdService;

	private final ChartService chartService;

	private final AccountService accountService;

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/subscription")
	public Mono<SubscriptionTrail.Response> getSubscriptionTrails(@RequestParam String accountNo,
			@RequestParam(defaultValue = "0") Integer pageNumber, @RequestParam(defaultValue = "10") Integer pageSize,
			@RequestParam(defaultValue = "DESC") String direction) {
		return trailService.getSubscriptionTrails(accountNo, pageNumber, pageSize, direction);
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/pub")
	public Mono<PubConcession.Response> getPubConcessions(@RequestParam(required = false) String accountNo,
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate fromDate,
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate toDate,
			@RequestParam(defaultValue = "0") Integer pageNumber, @RequestParam(defaultValue = "10") Integer pageSize,
			@RequestParam(defaultValue = "DESC") String direction) {
		return trailService.getPubConcessions(accountNo, fromDate, toDate, pageNumber, pageSize, direction);
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/pub/csv")
	public Flux<ResponseCsv> downloadPubConcessions(@RequestParam(required = false) String accountNo,
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate fromDate,
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate toDate) {
		return trailService.downloadPubConcessions(accountNo, fromDate, toDate);
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/meterReadings")
	public Mono<MeterReading.Response> getMeterReadings(@RequestParam String accountNo,
			@RequestParam(defaultValue = "0") Integer pageNumber, @RequestParam(defaultValue = "10") Integer pageSize,
			@RequestParam(defaultValue = "DESC") String direction) {
		return trailService.getMeterReadings(accountNo, pageNumber, pageSize, direction);
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/retrieveMeterReadDetails/{accountNo}")
	public Mono<RetrieveScalarMeterInfo.Meters> retrieveMeterReadDetails(@PathVariable String accountNo) {
		Mono<RetrieveScalarMeterInfo.Meters> response = smrdService
			.retrieveScalarMeterInfoDetails(new RetrieveScalarMeterInfo.AccountsSK(List.of(accountNo)));
		return response;
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/statistics/self-services")
	public Mono<ResponseEntity<MeterReadingSubmission.StatsResponse>> getMeterReadingByMonth(
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime startDate,
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime endDate) {
		return smrdService.getMeterReadingByMonth(startDate, endDate);
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@PostMapping("/monthly/usageTrend")
	public Mono<MDHChart.MDHChartResponse> retrieveMonthlyMeterReadDetails(
			@RequestBody MDHChart.MDHChartRequest request) {
		return chartService.retrieveMonthly(request, Mono.just(request.getIamId()));
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@PostMapping("/daily/usageTrend")
	public Mono<MDHChart.MDHChartResponse> retrieveDailyMeterReadDetails(@RequestBody MDHChart.DailySKRequest request) {
		return chartService.retrieveDaily(BDLChart.Daily.Request.getDailyRequestForGraph(request));
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@PostMapping("/hourly/usageTrend")
	public Mono<MDHChart.MDHChartResponse> retrieveHourlyMeterReadDetails(
			@RequestBody MDHChart.HourlySKRequest request) {
		return chartService.retrieveHourly(BDLChart.Hourly.Request.getHourlyRequestForGraph(request));
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@PostMapping(value = "/charts/csv/monthly")
	public Mono<ResponseEntity<String>> csvMonthly(@RequestBody MDHChart.MDHChartRequest request) {
		request.setConsumptionBy(CSV_MONTHLY);
		return chartService.downloadMonthlyChartCsv(request, Mono.just(request.getIamId()));
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@PostMapping(value = "/charts/csv/dailyHourly")
	public Mono<ResponseEntity<String>> dailyHourly(@RequestBody MDHChart.DailyHourlyCSVSKRequest request) {
		return chartService.downloadDailyHourlyCsv(request);
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/bill-preferences")
	public Mono<StatisticRpBillPrefRes> getBillPreferencesStatistic(
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime startDate,
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime endDate) {
		return accountService.countBillPreferences(startDate, endDate);
	}

	@Loggable
	@SkalboxM2MSecured(scopes = "read:spd.skalbox.trails")
	@GetMapping("/bill-preferences/exports")
	public Mono<byte[]> downloadBillPreferencesStatistic(
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime startDate,
			@RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime endDate) {
		return accountService.downloadBillPreferencesStatistic(startDate, endDate);
	}

}

package io.spdigital.skalbox.chart.web.controller;

import io.spdigital.skalbox.chart.model.dto.MDHChart;
import io.spdigital.skalbox.chart.model.dto.MDHChart.MDHChartRequest;
import io.spdigital.skalbox.chart.service.ChartService;
import io.spdigital.skalbox.logging.Loggable;
import io.spdigital.skalbox.service.security.Field;
import io.spdigital.skalbox.web.common.security.SkalboxSecured;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

import static io.spdigital.skalbox.chart.model.dto.ChartConstants.CSV_MONTHLY;
import static io.spdigital.skalbox.web.common.SkalboxConstants.PRIVATE_ENDPOINT;

@Slf4j
@RestController
@RequiredArgsConstructor
@RequestMapping(PRIVATE_ENDPOINT)
public class PrivateChartController {

	private final ChartService chartService;

	@Loggable
	@PostMapping(value = "/charts/csv/monthly")
	@SkalboxSecured(field = Field.ACCOUNT_NO)
	public Mono<ResponseEntity<String>> csvMonthly(@RequestBody MDHChartRequest request, ServerWebExchange exchange) {
		request.setConsumptionBy(CSV_MONTHLY);
		return chartService.downloadMonthlyCsv(request, exchange);
	}

	@Loggable
	@PostMapping(value = "/charts/csv/dailyHourly")
	@SkalboxSecured(field = Field.ACCOUNT_NOS)
	public Mono<ResponseEntity<String>> csvDailyHourly(@RequestBody MDHChart.DailyHourlyCSVSKRequest request) {
		return chartService.downloadDailyHourlyCsv(request);
	}

}

