package io.spdigital.skalbox.auth.service;

import io.spdigital.skalbox.config.ConnectionProperties;
import io.spdigital.skalbox.model.dto.JwtDecodedToken;
import io.spdigital.skalbox.service.ProfileApi;
import io.spdigital.skalbox.service.jwt.JwtService;
import io.spdigital.skalbox.service.security.SecurityService;
import io.spdigital.skalbox.util.ReactiveConnector;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;
import reactor.util.function.Tuple2;

import java.util.Arrays;
import java.util.Collections;
import java.util.List;
import java.util.Map;

import static io.spdigital.skalbox.config.ConnectionProperties.Host.PROFILEAPI;

@Slf4j
@Service
@RequiredArgsConstructor
public class Auth0ServiceImpl implements Auth0Service {

	private final SecurityService securityService;

	private final JwtService jwtService;

	private final ReactiveConnector reactiveConnector;

	private final int CHUNK = 10;

	public Mono<String> getAuth0Id(ServerWebExchange exchange) {

		return securityService.getTokenHeader(exchange).flatMap(jwtService::decode).map(JwtDecodedToken::getIamUserId);
	}

	public Mono<String> getAuth0EmailId(ServerWebExchange exchange) {

		return securityService.getTokenHeader(exchange).flatMap(jwtService::decode).map(JwtDecodedToken::getEmail);
	}

	public Mono<JwtDecodedToken> getAuth0DecodedToken(ServerWebExchange exchange) {
		return securityService.getTokenHeader(exchange).flatMap(jwtService::decode);
	}

	@Override
	public Mono<Map<String, String>> getAuth0IdsFromEmails(List<String> emails) {
		return Flux.range(0, ((emails.size()) + CHUNK - 1) / CHUNK)
			.flatMap(
					i -> reactiveConnector
						.reactiveGet(PROFILEAPI, ProfileApi.SearchUsers.URL,
								Map.of("emails",
										Arrays.asList(String.join(",",
												emails.subList(i * CHUNK, Math.min(emails.size(), (i + 1) * CHUNK))))),
								Collections.emptyMap(), ProfileApi.SearchUsers.Response.class)
						.doOnError(throwable -> log.error("auth0 /m2m/search-users failed :: Emails:{}, {} ", i,
								throwable.getMessage()))
						.onErrorReturn(ProfileApi.SearchUsers.Response.builder().build())
						.filter(resp -> (null != resp.getUsers()))
						.flatMapIterable(ProfileApi.SearchUsers.Response::getUsers))
			.collectMap(ProfileApi.SearchUsers.User::getEmail, ProfileApi.SearchUsers.User::getUserId);
	}

	@Override
	public Mono<Map<String, String>> getEmailsFromAuth0Ids(List<String> auth0Ids) {
		return Flux.range(0, ((auth0Ids.size()) + CHUNK - 1) / CHUNK)
			.flatMap(i -> reactiveConnector
				.reactiveGet(PROFILEAPI, ProfileApi.SearchUsers.URL,
						Map.of("iam_ids",
								Arrays.asList(String.join(",",
										auth0Ids.subList(i * CHUNK, Math.min(auth0Ids.size(), (i + 1) * CHUNK))))),
						Collections.emptyMap(), ProfileApi.SearchUsers.Response.class)
				.doOnError(throwable -> log.error("auth0 /m2m/search-users failed :: iam_ids:{}, {} ", i,
						throwable.getMessage()))
				.onErrorReturn(ProfileApi.SearchUsers.Response.builder().build())
				.filter(resp -> (null != resp.getUsers()))
				.flatMapIterable(ProfileApi.SearchUsers.Response::getUsers))
			.collectMap(ProfileApi.SearchUsers.User::getUserId, ProfileApi.SearchUsers.User::getEmail);
	}

	@Override
	public Mono<Map<String, String>> createAuth0AccountForList(List<ProfileApi.CreateUser.Request> createUsers) {
		return Flux.fromIterable(createUsers)
			.concatMap(createUser -> reactiveConnector
				.reactivePost(ConnectionProperties.Host.PROFILEAPI, ProfileApi.CreateUser.URL, createUser,
						ProfileApi.ProfileInfo.Response.class)
				.doOnError(throwable -> log.error("auth0 {} failed :: User:{}, Error:{} ", ProfileApi.CreateUser.URL,
						createUser, throwable.getMessage()))
				.onErrorReturn(ProfileApi.ProfileInfo.Response.builder().build())
				.map(resp -> ProfileApi.CreateUser.Response.builder()
					.email(createUser.getEmail())
					.iamId(resp.getIamId())
					.build()))
			.collectMap(resp -> resp.getEmail(), resp -> resp.getIamId());
	}

	@Override
	public Mono<Map<String, Boolean>> addScopes(List<String> iamUserIds, String permissions) {
		return Flux.fromIterable(iamUserIds)
			.concatMap(iamId -> reactiveConnector.reactivePost(PROFILEAPI, ProfileApi.AddScope.URL,
					ProfileApi.AddScope.createProfileRequest(iamId, permissions), ProfileApi.AddScope.Response.class)
				.doOnError(response -> log.error("addScopes :: failed for iamId: {}, error: {}", iamId,
						response.getMessage()))
				.onErrorResume(err -> Mono
					.just(ProfileApi.AddScope.Response.builder().status(false).error(err.getMessage()).build()))
				.map(ProfileApi.AddScope.Response::isStatus)
				.zipWith(Mono.just(iamId)))
			.collectMap(Tuple2::getT2, Tuple2::getT1);
	}

}

