package io.spdigital.skalbox.chart.model.dto;

import com.fasterxml.jackson.annotation.JsonProperty;
import io.spdigital.skalbox.chart.exception.ChartApiException;
import io.spdigital.skalbox.web.common.security.SecuredData;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;
import lombok.extern.slf4j.Slf4j;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.function.Function;

import static io.spdigital.skalbox.chart.model.dto.ChartConstants.*;
import static org.apache.commons.lang3.StringUtils.wrap;

public interface MDHChart {

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	class MDHChartRequest implements SecuredData {

		// Used to name CSV file for Monthly api only
		private String accountNo;

		// This will be populated only for M2M call
		private String iamId;

		@Builder.Default
		private String ebsPremiseNo = "";

		@Builder.Default
		private String msslPremiseNo = "";

		private String consumptionValue;

		private String consumptionBy;

	}

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	class DailySKRequest implements SecuredData {

		@Override
		public List<String> getAccountNos() {
			return accountNos;
		}

		private List<String> accountNos;

		private String month;

	}

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	class HourlySKRequest implements SecuredData {

		@Override
		public List<String> getAccountNos() {
			return accountNos;
		}

		private List<String> accountNos;

		private String date;

	}

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	class DailyHourlyCSVSKRequest implements SecuredData {

		@Override
		public List<String> getAccountNos() {
			return accountNos;
		}

		private List<String> accountNos;

		private String consumptionBy;

	}

	@Data
	@Slf4j
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	class MDHChartResponse {

		String premiseType;

		@JsonProperty("electricity")
		private Optional<UsageUtil> usageUtilElec;

		// Gas data not available for Daily & HalfHourly consumption
		@JsonProperty("gas")
		private Optional<UsageUtil> usageUtilGas;

		// Water data not available for Daily & HalfHourly consumption
		@JsonProperty("water")
		private Optional<UsageUtil> usageUtilWater;

		public static Function<Map, MDHChartResponse> getBdlResponseForDaily(BDLChart.Daily.Request req) {
			return consumptionMap -> {
				List<MDHChart.ConsumptionData> consumptions = new ArrayList<>();
				consumptionMap.forEach((k,
						v) -> consumptions.add(ConsumptionData.builder()
							.period(k.toString().replace("day_", "-"))
							.current(v.toString())
							.build()));

				if (!CSV_DAILY.equals(req.getConsumptionBy()) && consumptions.isEmpty()) {
					log.info("No data from BDL: Daily: accountNos {}, error {}", req.getAccountNos());
					throw new ChartApiException(CHART_NO_DATA_MSG, CHART_BDL_NO_DATA,
							String.format("AccNos: %s", req.getAccountNos()));
				}

				// consumptions is set for usageUtilElec as its not applicable for gas &
				// water
				return MDHChart.MDHChartResponse.builder()
					.usageUtilElec(
							Optional.of(MDHChart.UsageUtil.builder().unit("kWh").consumption(consumptions).build()))
					.build();
			};
		}

		public static Function<Map, MDHChartResponse> getBdlResponseForHourly(BDLChart.Hourly.Request req) {
			return consumptionMap -> {
				List<MDHChart.ConsumptionData> consumptions = new ArrayList<>();
				consumptionMap.forEach((k, v) -> {
					String key = k.toString();
					String period = key.substring(0, 10) + " " + key.charAt(12) + key.charAt(13) + ":" + key.charAt(14)
							+ key.charAt(15) + ":00";
					consumptions.add(MDHChart.ConsumptionData.builder().period(period).current(v.toString()).build());
				});

				if (!CSV_HOURLY.equals(req.getConsumptionBy()) && consumptions.isEmpty()) {
					log.info("No data from BDL: Hourly: accountNos {}, error {}", req.getAccountNos());
					throw new ChartApiException(CHART_NO_DATA_MSG, CHART_BDL_NO_DATA,
							String.format("AccNos: %s", req.getAccountNos()));
				}

				// consumptions is set for usageUtilElec as its not applicable for gas &
				// water
				return MDHChart.MDHChartResponse.builder()
					.usageUtilElec(
							Optional.of(MDHChart.UsageUtil.builder().unit("kWh").consumption(consumptions).build()))
					.build();
			};
		}

	}

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	class UsageUtil {

		private String unit;

		private String current;

		private String neighbourhood;

		private String efficient;

		private String comparisonType;

		private String comparisonMsgType;

		private String comparisonMsg;

		private List<ConsumptionData> consumption;

	}

	@Data
	@Builder
	@NoArgsConstructor
